head.script:
scwin.hd_kcomcd = "DBEX"; //House BL조회 확인
scwin.strCurDate;
scwin.strPreDate;
scwin.mhio;

/**
 * event
 * @name onpageload
 * @description
 */
scwin.onpageload = function () {
    // 세션정보 가져오기
    // 초기값 설정 - 날짜 (현재날짜, 1달전 날짜)
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.strPreDate = $c.date.addDate(scwin.strCurDate, -2);

    loginClntNo = $c.data.getMemInfo("clntNo") ?? "";
    loginClntNm = $c.data.getMemInfo("clntNm") ?? "";    //거래처명
    userClsCd = $c.data.getMemInfo("userClsCd") ?? "";  	// 사용자 구분코드
};

/**
* event
* @name onUdcCompleted
* @description UDC 초기화 후 이벤트
*/
scwin.onUdcCompleted = function () {
    cnd_ed_mhetdFrom.options.title = "ETD From";
    cnd_ed_mhetdTo.options.title = "ETD To";
    cnd_ed_mhetaFrom.options.title = "ETA From";
    cnd_ed_mhetaTo.options.title = "ETA To";

    let param = $c.data.getParameter();
    scwin.mhio = param?.mhio ?? param?.menuInfo?.menuParam?.mhio;
    scwin.f_set("ONLOAD");
    scwin.f_dateLoading();
};

/**
 * event
 * @name f_set
 * @description 화면 open시 초기 데이타 setting
 */
scwin.f_set = function (gubun) {
    switch (gubun) {
        case "ONLOAD":
            $c.gus.cfDisableKey();

            cnd_ed_mhetdFrom.setValue(scwin.strPreDate);
            cnd_ed_mhetdTo.setValue(scwin.strCurDate);

            cnd_ed_mhmblno.focus();
            cnd_rd_mhio.setValue(scwin.mhio);
            break;

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
            break;

        case "DELETE":
            $c.gus.cfDisableBtn();
            break;
    }
};

/**
 * event
 * @name f_Retrieve
 * @description 조회
 */
scwin.f_Retrieve = async function () {
    if (cnd_rd_mhio.getValue() == "O") {
        // 날짜  From - To 입력 확인
        if (!await $c.gus.cfValidate([cnd_ed_mhetdFrom, cnd_ed_mhetdTo])) {
            return;
        }
        // 날짜 범위 확인
        if (!$c.gus.cfIsAfterDate(cnd_ed_mhetdFrom.getValue(), cnd_ed_mhetdTo.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD From", "ETD To"));  //@은(는) 보다 작아야 합니다.
            cnd_ed_mhetdFrom.focus();
            return;
        }
    } else {
        // 날짜  From - To 입력 확인
        if (!await $c.gus.cfValidate([cnd_ed_mhetaFrom, cnd_ed_mhetaTo])) {
            return;
        }
        if (!$c.gus.cfIsAfterDate(cnd_ed_mhetaFrom.getValue(), cnd_ed_mhetaTo.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETA From", "ETA To"));  //@은(는) 보다 작아야 합니다.
            cnd_ed_mhetaFrom.focus();
            return;
        }
    }

    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    $c.sbm.execute(sbm_retrieve);
};

/**
 * event
 * @name f_FieldClear
 * @description 조회 조건 지우기
 */
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_searchCondition); // 조회조건의 테이블을 초기화.
    scwin.f_set("ONLOAD");
};

/**
