/**
 * event
 * @name f_OpenCommonPopUp
 * @description 공통팝업 열기
 */
scwin.f_OpenCommonPopUp = function (gubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (gubun) {
        case "Vessel":
            udc_mhvsl.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, cnd_ed_mhvslcd, cnd_txt_mhvsl)
                , cnd_ed_mhvslcd.getValue().trim()
                , cnd_txt_mhvsl.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Vessel,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Loading":
            udc_mhlod.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, cnd_ed_mhlodcd, cnd_txt_mhlodnm)
                , cnd_ed_mhlodcd.getValue().trim()
                , cnd_txt_mhlodnm.getValue()
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Loading,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "Discharge":
            udc_mhdisc.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, cnd_ed_mhdisccd, cnd_txt_mhdiscnm)
                , cnd_ed_mhdisccd.getValue().trim()
                , cnd_txt_mhdiscnm.getValue()
                , pWinCloseTF
                , '6'
                , 'Code, Name,,,, UNCODE'
                , '80,160,,,,80'
                , "3,4,5,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "Discharge,Code,Name"
                , pNoDataCloseTF
            );
            break;

        case "DEPT":
            udc_dept.ilCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, cnd_ed_deptCd, cnd_txt_deptNm)
                , cnd_ed_deptCd.getValue().trim()
                , cnd_txt_deptNm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "DEPT,Code,Name"
                , pNoDataCloseTF
            );
            break;
    }
};

/**
 * event
 * @name f_downExcelSheet
 * @description 엑셀다운로드
 */
scwin.f_downExcelSheet = async function () {
    if (ds_masterblList.getRowCount()) {
        let cfrm = await $c.win.confirm("Master B/L List를 EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_masterblList, { fileName: "Master BL List.xlsx", sheetName: "Master BL List" });
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

/**
 * event
 * @name f_dateLoading
 * @description hhio에따른 date default
 */
scwin.f_dateLoading = function () {
    if (cnd_rd_mhio.getValue() == "O") {
        cnd_ed_mhetdFrom.setValue(scwin.strPreDate);
        cnd_ed_mhetdTo.setValue(scwin.strCurDate);
        cnd_ed_mhetaFrom.setValue("");
        cnd_ed_mhetaTo.setValue("");
    } else {
        cnd_ed_mhetdFrom.setValue("");
        cnd_ed_mhetdTo.setValue("");
        cnd_ed_mhetaFrom.setValue(scwin.strPreDate);
        cnd_ed_mhetaTo.setValue(scwin.strCurDate);
    }
};

/**
 * event
 * @name f_Tracking
 * @description 선사 트래킹
 */
scwin.f_Tracking = async function () {
    //구현 불가능한 기능, 버튼 안보이도록 처리해서 막음
    return;
    if (!ds_masterblList.getRowCount()) {
        await $c.win.alert("선사 Tracking 할 Master B/L을 조회해 주세요.");
        return;
    }

    let row = gr_masterblList.getFocusedRowIndex();
    dma_retrieveCode.setJSON({
        "grpCd": "IL052",
        "cd": ds_masterblList.getCellData(row, "mhlinercd")
    });

    await $c.sbm.execute(sbm_retrieveCodeCMD);

    let vline = "";
    if (ds_liner.getRowCount() > 0 && ds_liner.getCellData(0, "cdNm") != "") {
        vline = ds_liner.getCellData(0, "cdNm");
    }

    let vparm = ds_masterblList.getCellData(row, "mhmblno");
    let objWSH = new ActiveXObject("WScript.Shell");
    let retval = objWSH.Run("C:\dbexp_scrap1\\upgrade.exe job=blsearch" + "&linecode=" + vline + "&no=" + vparm + "&", 1, true);
};

/**
 * event
 * @name f_ProgramDownload
 * @description 선사 트래킹 프로그램 다운로드
 */
scwin.f_ProgramDownload = function () {
    //버튼 안보이도록 처리해서 막음
    return;
    window.open("ftp://172.21.1.42:7000/Home/Setup/Setup_CarrierAPI.exe");
};

/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
    let rowCnt = ds_masterblList.getRowCount();
    totalRows_item.setValue(rowCnt); // 조회된 건수를 매출입항목Grid 하단에 표시한다.
    if (ds_masterblList.getRowCount()) {
        scwin.f_set("RETRIEVE");
        gr_masterblList.setFocusedCell(0, gr_masterblList.getFocusedColumnIndex() ?? 0, false);
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

/**
 * event
 * @name cnd_rd_mhio_onviewchange
 * @description
 */
scwin.cnd_rd_mhio_onviewchange = function (info) {
    scwin.f_dateLoading();
};

/**
 * event
 * @name gr_masterblList_oncelldblclick
 * @description
 */
scwin.gr_masterblList_oncelldblclick = function (row, col, colid) {
    // BL세부사항 조회
    const mhio = ds_masterblList.getCellData(row, "mhio");
    let param = {
        "linkcheck": "3",
        "kcomcd": scwin.hd_kcomcd,
        "blno": "",
        "mhno": ds_masterblList.getCellData(row, "mhno"),
    };
    if (mhio == "O") {  //outBound
        $c.win.openMenu($p, "Export Master B/L", "/ui/il/seaout/sobl/se_106_01_01b.xml", "se_106_01_01b", param, { openAction: "exist" });
    } else {  // inbound
        $c.win.openMenu($p, "Import Master B/L", "/ui/il/seainb/sibl/se_202_01_01b.xml", "se_202_01_01b", param, { openAction: "exist" });
    }
};

